    // Parse HTML and inject content at specified locations
    let body = response.body.data.toString('utf-8');
    const injectionArray = JSON.parse(injectionPoints);

    for (const { selector, content } of injectionArray) {
        const regex = new RegExp(`(${selector})`, 'gi');
        body = body.replace(regex, `$1${content}`);
    }

    // Update response body
    response.body.data = Buffer.from(body, 'utf-8');
    response.body.encoding = 'utf-8';
    response.headers['content-length'] = [{ key: 'Content-Length', value: `${Buffer.byteLength(response.body.data)}` }];

